mapper.select:
select

from tc_pollination_tb

    and experiment_num=#{experimentNum,jdbcType=VARCHAR}
    and sample_apply_num=#{sampleApplyNum,jdbcType=VARCHAR}
    and pollination_apply_num=#{pollinationApplyNum,jdbcType=VARCHAR}
    and m_region_num=#{mRegionNum,jdbcType=VARCHAR}
    and f_region_num=#{fRegionNum,jdbcType=VARCHAR}
    and m_sample_code=#{mSampleCode,jdbcType=VARCHAR}
    and f_sample_code=#{fSampleCode,jdbcType=VARCHAR}
    and m_seed_num=#{mSeedNum,jdbcType=VARCHAR}
    and f_seed_num=#{fSeedNum,jdbcType=VARCHAR}
    and f_breed_name=#{fBreedName,jdbcType=VARCHAR}
    and m_breed_name=#{mBreedName,jdbcType=VARCHAR}
    and m_vector_task_code=#{mVectorTaskCode,jdbcType=VARCHAR}
    and f_vector_task_code=#{fVectorTaskCode,jdbcType=VARCHAR}
    and m_generation_code=#{mGenerationCode,jdbcType=VARCHAR}
    and f_generation_code=#{fGenerationCode,jdbcType=VARCHAR}
    and m_tc_gene=#{mTcGene,jdbcType=VARCHAR}
    and f_tc_gene=#{fTcGene,jdbcType=VARCHAR}
    and pollination_date=#{pollinationDate,jdbcType=VARCHAR}

        and   pollination_method_code=#{pollinationMethodCode,jdbcType=VARCHAR}


        and  pollination_method_name=#{pollinationMethodName,jdbcType=VARCHAR}

    and harvest_type_code=#{harvestTypeCode,jdbcType=VARCHAR}
    and harvest_type_name=#{harvestTypeName,jdbcType=VARCHAR}
    and remark=#{remark,jdbcType=VARCHAR}

order by id desc
